import base from '../base'

//拿到链接
function LoginLink(AppUrlMysqlName , XkfMysqlName , Account , LoginHost , LoginUrl , callBack) {
    base.BasePost(
        '/api/LoginLink',
        {
            AppUrlMysqlName : AppUrlMysqlName,
            XkfMysqlName : XkfMysqlName,
            Account: Account,
            LoginHost: LoginHost,
            LoginUrl : LoginUrl,
        },
        function (response) {
            callBack(response)
        }
    )
}

export default {
    LoginLink,
}
